    {"id":"scrum","name":"Scrum","category":"sdlc","icon":"SC","difficulty":"Intermediate","tags":["Sprints","Team Roles","Ceremonies"],"description":"Agile framework using fixed-length sprints and defined team roles.","best_for":"Teams delivering incremental value with frequent reviews.","advantages":["Predictable sprint rhythm","High team transparency"],"limitations":["Ceremony overhead possible","Requires disciplined team participation"],"recommended_when":"You need structured agile delivery and clear cadence.","avoid_when":"Team is too small for role and ceremony overhead.","example_project":"Coursework app delivered in two-week sprint cycles.","beginner_advice":"Keep sprint goals small and measurable.","learning_path":["Learn Scrum roles/events","Run a sample sprint"],"references":["Official docs","W3Schools","GeeksforGeeks"]},
    {"id":"kanban","name":"Kanban","category":"sdlc","icon":"KB","difficulty":"Beginner-Friendly","tags":["Flow","Visual Management","Continuous Delivery"],"description":"Workflow method focusing on visualizing work and limiting work in progress.","best_for":"Teams needing continuous flow and flexible priorities.","advantages":["Easy adoption","Improves throughput visibility"],"limitations":["Less timeboxed structure","Can hide long-term planning gaps"],"recommended_when":"You want continuous delivery with flexible task movement.","avoid_when":"You need strict sprint cadence and ceremonies.","example_project":"Support ticket workflow managed on visual board.","beginner_advice":"Set clear WIP limits and review blocked tasks daily.","learning_path":["Set up Kanban board","Track flow and cycle time"],"references":["Official docs","W3Schools","GeeksforGeeks"]},
    {"id":"devops","name":"DevOps","category":"sdlc","icon":"DO","difficulty":"Intermediate","tags":["CI/CD","Automation","Operations"],"description":"Culture and practices integrating development and operations for faster delivery.","best_for":"Teams shipping frequently with automated pipelines.","advantages":["Faster releases","Improved reliability via automation"],"limitations":["Tooling complexity","Needs cross-team culture change"],"recommended_when":"You need repeatable deployments and rapid iteration.","avoid_when":"Team cannot maintain automation pipelines yet.","example_project":"Automated CI/CD for campus management platform.","beginner_advice":"Start with basic CI tests before full CD automation.","learning_path":["Set up CI pipeline","Add deployment automation"],"references":["Official docs","W3Schools","GeeksforGeeks"]},
    {"id":"lean","name":"Lean","category":"sdlc","icon":"LN","difficulty":"Intermediate","tags":["Waste Reduction","Efficiency","Value"],"description":"Process model focused on maximizing value while minimizing waste.","best_for":"Teams optimizing process efficiency and delivery focus.","advantages":["Encourages efficiency","Focuses on customer value"],"limitations":["Requires disciplined measurement","May under-document if misapplied"],"recommended_when":"You want to remove bottlenecks and non-value tasks.","avoid_when":"Organization needs heavy formal documentation for compliance.","example_project":"Product team streamlining delivery workflow metrics.","beginner_advice":"Track cycle time and remove one bottleneck at a time.","learning_path":["Map value stream","Iteratively remove waste"],"references":["Official docs","W3Schools","GeeksforGeeks"]},
    {"id":"big-bang-model","name":"Big Bang Model","category":"sdlc","icon":"BB","difficulty":"Beginner-Friendly","tags":["Minimal Planning","Experiment","Small Projects"],"description":"Model with little formal process, useful for small experimental work.","best_for":"Tiny projects or quick proof-of-concept experiments.","advantages":["Very low process overhead","Fast start"],"limitations":["High uncertainty and risk","Poor predictability"],"recommended_when":"Scope is small and exploratory.","avoid_when":"Project has strict deadlines, budget, or quality requirements.","example_project":"Hackathon prototype built in a short sprint.","beginner_advice":"Limit scope strictly and document assumptions quickly.","learning_path":["Define tiny goal","Build and evaluate prototype"],"references":["Official docs","W3Schools","GeeksforGeeks"]},
    {"id":"fdd","name":"Feature-Driven Development","category":"sdlc","icon":"FD","difficulty":"Intermediate","tags":["Feature-centric","Team Planning","Incremental"],"description":"Model organizing work around designing and building by feature sets.","best_for":"Large teams delivering frequent feature increments.","advantages":["Clear feature ownership","Progress is easy to track by feature"],"limitations":["Needs strong upfront domain modeling","Less suited for tiny teams"],"recommended_when":"Project scope can be split into clear business features.","avoid_when":"Requirements are too fluid to define feature hierarchy.","example_project":"Academic ERP delivered by feature domains.","beginner_advice":"Start with a small feature list and clear ownership.","learning_path":["Create feature list","Plan and deliver feature sets"],"references":["Official docs","W3Schools","GeeksforGeeks"]},
